// Tests for solveHomophonicSubstitution. Hill-climbing is stochastic
// even with a fixed seed; we test the deterministic shape of the output
// alongside one expensive recovery test on a long English passage.

import { describe, it, expect } from 'vitest';
import {
  solveHomophonicSubstitution,
  type HomophonicSolverArgs,
} from '../src/homophonic-substitution-solver';

const TALE_OF_TWO_CITIES = (
  'It was the best of times it was the worst of times it was the age ' +
  'of wisdom it was the age of foolishness it was the epoch of belief ' +
  'it was the epoch of incredulity it was the season of light it was ' +
  'the season of darkness it was the spring of hope it was the winter ' +
  'of despair we had everything before us we had nothing before us we ' +
  'were all going direct to heaven we were all going direct the other way'
).toUpperCase();

function buildRandomPermutation(seed: number): Map<string, string> {
  const letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');
  let s = seed >>> 0;
  const next = () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s;
  };
  // Fisher-Yates shuffle.
  const shuffled = [...letters];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = next() % (i + 1);
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  const m = new Map<string, string>();
  for (let i = 0; i < 26; i++) m.set(letters[i], shuffled[i]);
  return m;
}

function encryptWithPermutation(
  plaintext: string,
  mapping: Map<string, string>,
): string {
  let out = '';
  for (const c of plaintext.toUpperCase()) {
    if (c >= 'A' && c <= 'Z') {
      out += mapping.get(c) ?? c;
    } else {
      out += c;
    }
  }
  return out;
}

function characterAccuracy(a: string, b: string): number {
  const minLen = Math.min(a.length, b.length);
  if (minLen === 0) return 0;
  let match = 0;
  for (let i = 0; i < minLen; i++) {
    if (a[i] === b[i]) match++;
  }
  return match / minLen;
}

describe('solveHomophonicSubstitution', () => {
  it(
    'recovers a simple monoalphabetic substitution on a long English passage',
    () => {
      const perm = buildRandomPermutation(0xabcd);
      const ciphertext = encryptWithPermutation(TALE_OF_TWO_CITIES, perm);
      const result = solveHomophonicSubstitution({
        ciphertext,
        forks: 8,
        seed: 0xcafe,
        maxSwapsPerFork: 8000,
        stagnationLimit: 400,
      });
      const accuracy = characterAccuracy(result.plaintext, TALE_OF_TWO_CITIES);
      // Honest scope: hill-climbing can get stuck in local optima even on
      // a simple 1-to-1 substitution. With 8 random restarts and a tight
      // budget, we get >> random (3.85%) but typically not full recovery.
      // Real production solvers use simulated annealing + n-gram-aware
      // large-step moves to reliably hit 95%+. >= 0.30 is well above
      // random and shows the algorithm makes English-shaped progress.
      expect(accuracy).toBeGreaterThanOrEqual(0.30);
    },
    60_000,
  );

  it('output shape: candidates length, ranks, sorting, buleyWeights', () => {
    const perm = buildRandomPermutation(0x1357);
    const ciphertext = encryptWithPermutation(TALE_OF_TWO_CITIES, perm);
    const forks = 6;
    const result = solveHomophonicSubstitution({
      ciphertext,
      forks,
      seed: 0x42,
      // Keep this fast: it's a shape test, not a recovery test.
      maxSwapsPerFork: 500,
      stagnationLimit: 50,
    });
    expect(result.candidates.length).toBe(forks);
    expect(result.candidates[0].rank).toBe(0);
    // Descending sort.
    for (let i = 1; i < result.candidates.length; i++) {
      expect(result.candidates[i - 1].score).toBeGreaterThanOrEqual(
        result.candidates[i].score,
      );
      expect(result.candidates[i].rank).toBe(i);
    }
    // buleyeanWeight(R, v) = R - min(v, R) + 1; with R=forks, v=rank:
    //   rank 0 → forks + 1
    //   rank forks-1 → 2
    expect(result.candidates[0].buleyWeight).toBe(forks + 1);
    expect(result.candidates[forks - 1].buleyWeight).toBe(2);
  });

  it('validation: empty ciphertext throws RangeError', () => {
    expect(() =>
      solveHomophonicSubstitution({ ciphertext: '' } as HomophonicSolverArgs),
    ).toThrow(RangeError);
  });

  it('validation: forks < 1 throws', () => {
    expect(() =>
      solveHomophonicSubstitution({
        ciphertext: 'ABCDEFG',
        forks: 0,
      }),
    ).toThrow(RangeError);
  });

  it('validation: maxSwapsPerFork < 100 throws', () => {
    expect(() =>
      solveHomophonicSubstitution({
        ciphertext: 'ABCDEFG',
        maxSwapsPerFork: 50,
      }),
    ).toThrow(RangeError);
  });

  it('determinism: same seed twice gives the same result', () => {
    const perm = buildRandomPermutation(0x9999);
    const ciphertext = encryptWithPermutation(TALE_OF_TWO_CITIES, perm);
    const args: HomophonicSolverArgs = {
      ciphertext,
      forks: 4,
      seed: 0xdeadbeef,
      maxSwapsPerFork: 600,
      stagnationLimit: 60,
    };
    const a = solveHomophonicSubstitution(args);
    const b = solveHomophonicSubstitution(args);
    expect(b.plaintext).toBe(a.plaintext);
    expect(b.score).toBe(a.score);
    expect(b.candidates.length).toBe(a.candidates.length);
    for (let i = 0; i < a.candidates.length; i++) {
      expect(b.candidates[i].score).toBe(a.candidates[i].score);
      expect(b.candidates[i].plaintext).toBe(a.candidates[i].plaintext);
      expect(b.candidates[i].swapCount).toBe(a.candidates[i].swapCount);
    }
  });

  it('whitespace preserved at the same positions', () => {
    const perm = buildRandomPermutation(0x2468);
    const ciphertext = encryptWithPermutation(TALE_OF_TWO_CITIES, perm);
    const result = solveHomophonicSubstitution({
      ciphertext,
      forks: 2,
      seed: 0x101,
      maxSwapsPerFork: 300,
      stagnationLimit: 30,
    });
    expect(result.plaintext.length).toBe(ciphertext.length);
    for (let i = 0; i < ciphertext.length; i++) {
      const cipherIsWs = /\s/.test(ciphertext[i]);
      const plainIsWs = /\s/.test(result.plaintext[i]);
      expect(plainIsWs).toBe(cipherIsWs);
      if (cipherIsWs) {
        expect(result.plaintext[i]).toBe(ciphertext[i]);
      }
    }
  });
});
